package dev.harrison.rendacomcarro.shared.web;
import dev.harrison.rendacomcarro.attachment.application.InvalidAttachmentException;import dev.harrison.rendacomcarro.shared.domain.*;import jakarta.servlet.http.HttpServletRequest;import java.util.UUID;import org.slf4j.*;import org.springframework.http.HttpStatus;import org.springframework.ui.Model;import org.springframework.web.bind.annotation.*;
@ControllerAdvice public class GlobalExceptionHandler {private static final Logger log=LoggerFactory.getLogger(GlobalExceptionHandler.class);@ExceptionHandler({DomainValidationException.class,IllegalArgumentException.class,InvalidAttachmentException.class})@ResponseStatus(HttpStatus.BAD_REQUEST)String badRequest(RuntimeException e,Model m){m.addAttribute("message",e.getMessage());return"errors/400";}@ExceptionHandler(ResourceNotFoundException.class)@ResponseStatus(HttpStatus.NOT_FOUND)String notFound(RuntimeException e,Model m){m.addAttribute("message",e.getMessage());return"errors/404";}@ExceptionHandler(DomainConflictException.class)@ResponseStatus(HttpStatus.CONFLICT)String conflict(RuntimeException e,Model m){m.addAttribute("message",e.getMessage());return"errors/409";}@ExceptionHandler(Exception.class)@ResponseStatus(HttpStatus.INTERNAL_SERVER_ERROR)String unexpected(Exception e,HttpServletRequest request,Model m){String correlation=UUID.randomUUID().toString();log.error("Unexpected error correlationId={} path={}",correlation,request.getRequestURI(),e);m.addAttribute("correlationId",correlation);m.addAttribute("message","Não foi possível concluir a operação.");return"errors/500";}}
